static common_chat_params common_chat_params_init_mistral_instruct_v3(const common_chat_template &          tmpl,
                                                                      const autoparser::generation_params & inputs) {
    GGML_UNUSED(tmpl);
    common_chat_params data;

    std::string prompt = "<s>";
    std::string pending_system;

    for (const auto & msg : inputs.messages) {
        auto role    = msg.value("role", "");
        auto content = msg.value("content", "");

        if (role == "system") {
            pending_system = content;
        } else if (role == "user") {
            if (!pending_system.empty()) {
                prompt += "[INST] " + pending_system + "\n" + content + " [/INST]";
                pending_system.clear();
            } else {
                prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            prompt += content + "</s>";
        }
    }

    data.prompt = prompt;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
}

std::optional<common_chat_params> common_chat_try_specialized_template(
        const common_chat_template &          tmpl,
        const std::string &                   src,
        const autoparser::generation_params & params) {
    // Ministral/Mistral Large 3 - uses special reasoning structure fixes, can't use autoparser
    // Note: Mistral Small 3.2 uses [CALL_ID] which Ministral doesn't have, so we can distinguish them
    if (src.find("[SYSTEM_PROMPT]") != std::string::npos && src.find("[TOOL_CALLS]") != std::string::npos &&
        src.find("[ARGS]") != std::string::npos && src.find("[CALL_ID]") == std::string::npos) {
        LOG_DBG("Using specialized template: Ministral/Magistral Large 3\n");
        return common_chat_params_init_ministral_3(tmpl, params);
    }

    // Mistral Instruct v0.3 - uses [INST]/[/INST] markers without [SYSTEM_PROMPT]
    if (src.find("[INST]") != std::string::npos &&
        src.find("[/INST]") != std::string::npos &&
        src.find("[SYSTEM_PROMPT]") == std::string::npos) {
        LOG_DBG("Using specialized template: Mistral Instruct v3\n");
        return common_chat_params_init_mistral_instruct_v3(tmpl, params);
    }

    // GPT-OSS - has unique channel-based structure that needs dedicated handler
